css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #f6faf6; color: #1a2e1a; }
.navbar { display: flex; align-items: center; justify-content: space-between; padding: 18px 60px; gap: 20px; background: white; border-bottom: 1px solid #e6f0e6; }
.brand { font-size: 19px; font-weight: 800; flex-shrink: 0; }
.search-box { flex: 1; max-width: 400px; }
.search-box input { width: 100%; padding: 12px 18px; border-radius: 999px; border: 1px solid #e6f0e6; background: #f6faf6; font-size: 14px; outline: none; }
.cart-icon { font-size: 15px; font-weight: 700; cursor: pointer; flex-shrink: 0; }
.categories { display: flex; gap: 10px; padding: 20px 60px; overflow-x: auto; }
.cat-chip { background: white; border: 1px solid #e6f0e6; color: #6b8e6b; padding: 10px 18px; border-radius: 999px; font-size: 13.5px; font-weight: 700; cursor: pointer; white-space: nowrap; }
.cat-chip.active { background: #16a34a; color: white; border-color: #16a34a; }
.products { padding: 0 60px 60px; }
.product-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(180px, 1fr)); gap: 18px; }
.product-card { background: white; border-radius: 16px; padding: 16px; border: 1px solid #e6f0e6; cursor: pointer; transition: 0.15s; }
.product-card:hover { box-shadow: 0 10px 24px rgba(22,163,74,0.08); }
.product-img { aspect-ratio: 1; background: #f0f7f0; border-radius: 12px; display: flex; align-items: center; justify-content: center; font-size: 40px; margin-bottom: 10px; }
.product-card h3 { font-size: 14px; font-weight: 700; margin-bottom: 4px; }
.unit { font-size: 12px; color: #9caf9c; margin-bottom: 8px; display: block; }
.price-row { display: flex; justify-content: space-between; align-items: center; }
.price { font-size: 15px; font-weight: 800; color: #16a34a; }
.add-btn { background: #f0f7f0; border: none; color: #16a34a; width: 30px; height: 30px; border-radius: 8px; font-size: 16px; font-weight: 800; cursor: pointer; }
.cart-drawer { position: fixed; top: 0; right: -380px; width: 360px; height: 100%; background: white; box-shadow: -10px 0 40px rgba(0,0,0,0.1); z-index: 20; transition: right 0.3s; display: flex; flex-direction: column; }
.cart-drawer.open { right: 0; }
.cart-header { display: flex; justify-content: space-between; align-items: center; padding: 24px; border-bottom: 1px solid #e6f0e6; }
.cart-header h2 { font-size: 18px; font-weight: 800; }
.cart-header button { background: none; border: none; font-size: 18px; cursor: pointer; }
.cart-items { flex: 1; overflow-y: auto; padding: 16px 24px; display: flex; flex-direction: column; gap: 14px; }
.cart-item { display: flex; gap: 14px; align-items: center; }
.cart-item-img { width: 48px; height: 48px; background: #f0f7f0; border-radius: 10px; display: flex; align-items: center; justify-content: center; font-size: 20px; flex-shrink: 0; }
.cart-item-info { flex: 1; }
.cart-item-info h4 { font-size: 13.5px; font-weight: 700; }
.cart-item-info span { font-size: 12.5px; color: #9caf9c; }
.qty-controls { display: flex; align-items: center; gap: 8px; }
.qty-controls button { width: 24px; height: 24px; border-radius: 6px; background: #f0f7f0; border: none; font-size: 13px; font-weight: 700; cursor: pointer; color: #16a34a; }
.cart-footer { padding: 24px; border-top: 1px solid #e6f0e6; }
.cart-total { display: flex; justify-content: space-between; font-size: 16px; font-weight: 800; margin-bottom: 16px; }
.btn-primary.full { width: 100%; background: #16a34a; color: white; border: none; padding: 15px; border-radius: 12px; font-size: 14px; font-weight: 700; cursor: pointer; }
.overlay { position: fixed; inset: 0; background: rgba(0,0,0,0.3); display: none; z-index: 19; }
.overlay.show { display: block; }
@media (max-width: 900px) { .navbar, .categories, .products { padding-left: 24px; padding-right: 24px; } .search-box { display: none; } .cart-drawer { width: 100%; right: -100%; } }

