const products = [
  { id: 1, name: 'Organik Domates', cat: 'fruit', unit: '1 kg', price: 24.90, emoji: '🍅' },
  { id: 2, name: 'Tam Yağlı Süt', cat: 'dairy', unit: '1 L', price: 32.50, emoji: '🥛' },
  { id: 3, name: 'Tam Buğday Ekmek', cat: 'bakery', unit: '500 g', price: 18.00, emoji: '🍞' },
  { id: 4, name: 'Badem', cat: 'snack', unit: '200 g', price: 64.90, emoji: '🌰' },
  { id: 5, name: 'Muz', cat: 'fruit', unit: '1 kg', price: 28.90, emoji: '🍌' },
  { id: 6, name: 'Yoğurt', cat: 'dairy', unit: '500 g', price: 22.50, emoji: '🥣' },
  { id: 7, name: 'Kruvasan', cat: 'bakery', unit: '4 adet', price: 39.90, emoji: '🥐' },
  { id: 8, name: 'Patates Cipsi', cat: 'snack', unit: '150 g', price: 34.90, emoji: '🥔' },
  { id: 9, name: 'Avokado', cat: 'fruit', unit: '2 adet', price: 46.00, emoji: '🥑' },
  { id: 10, name: 'Beyaz Peynir', cat: 'dairy', unit: '400 g', price: 89.90, emoji: '🧀' },
  { id: 11, name: 'Çikolata', cat: 'snack', unit: '100 g', price: 29.90, emoji: '🍫' },
  { id: 12, name: 'Brokoli', cat: 'fruit', unit: '500 g', price: 19.90, emoji: '🥦' }
];

let cart = {};
let currentCategory = 'all';
let searchQuery = '';

function renderProducts() {
  const grid = document.getElementById('productGrid');
  grid.innerHTML = '';
  products
    .filter(p => currentCategory === 'all' || p.cat === currentCategory)
    .filter(p => p.name.toLowerCase().includes(searchQuery.toLowerCase()))
    .forEach(p => {
      const card = document.createElement('div');
      card.className = 'product-card';
      card.innerHTML = `
        <div class="product-img">${p.emoji}</div>
        <h3>${p.name}</h3>
        <span class="unit">${p.unit}</span>
        <div class="price-row">
          <span class="price">₺${p.price.toFixed(2)}</span>
          <button class="add-btn" onclick="addToCart(${p.id})">+</button>
        </div>
      `;
      grid.appendChild(card);
    });
}

function filterCategory(btn, cat) {
  currentCategory = cat;
  document.querySelectorAll('.cat-chip').forEach(c => c.classList.remove('active'));
  btn.classList.add('active');
  renderProducts();
}

function searchProducts(query) {
  searchQuery = query;
  renderProducts();
}

function addToCart(id) {
  cart[id] = (cart[id] || 0) + 1;
  updateCart();
  toggleCart(true);
}

function changeCartQty(id, delta) {
  cart[id] = (cart[id] || 0) + delta;
  if (cart[id] <= 0) delete cart[id];
  updateCart();
}

function updateCart() {
  const totalItems = Object.values(cart).reduce((a, b) => a + b, 0);
  document.getElementById('cartCount').textContent = totalItems;

  const itemsContainer = document.getElementById('cartItems');
  itemsContainer.innerHTML = '';
  let total = 0;
  Object.entries(cart).forEach(([id, qty]) => {
    const p = products.find(pr => pr.id === parseInt(id));
    if (!p) return;
    total += p.price * qty;
    const div = document.createElement('div');
    div.className = 'cart-item';
    div.innerHTML = `
      <div class="cart-item-img">${p.emoji}</div>
      <div class="cart-item-info"><h4>${p.name}</h4><span>₺${p.price.toFixed(2)} / ${p.unit}</span></div>
      <div class="qty-controls">
        <button onclick="changeCartQty(${p.id}, -1)">−</button>
        <span>${qty}</span>
        <button onclick="changeCartQty(${p.id}, 1)">+</button>
      </div>
    `;
    itemsContainer.appendChild(div);
  });
  document.getElementById('cartTotal').textContent = `₺${total.toFixed(2)}`;
}

function toggleCart(forceOpen) {
  const drawer = document.getElementById('cartDrawer');
  const overlay = document.getElementById('overlay');
  const shouldOpen = forceOpen !== undefined ? forceOpen : !drawer.classList.contains('open');
  drawer.classList.toggle('open', shouldOpen);
  overlay.classList.toggle('show', shouldOpen);
}

renderProducts();
